import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/linux-java-version.Bae4eMgj.js";const a=JSON.parse(`{"title":"Java auf Linux installieren","description":"Eine Schritt-für-Schritt-Anleitung zur Installation von Java auf Linux.","frontmatter":{"title":"Java auf Linux installieren","description":"Eine Schritt-für-Schritt-Anleitung zur Installation von Java auf Linux.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"de_de/1.20.4/players/installing-java/linux.md","filePath":"versions/1.20.4/translated/de_de/players/installing-java/linux.md","lastUpdated":1739538073000}`);var o={name:`de_de/1.20.4/players/installing-java/linux.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Java auf Linux installieren <a class="header-anchor" href="#h1" aria-label="Permalink to “Java auf Linux installieren”">​</a></h1><p>Diese Anleitung führt Sie durch die Installation von Java 17 auf Linux.</p><h2 id="_1-uberprufen-ob-java-bereits-installiert-ist" tabindex="-1">1. Überprüfen, ob Java bereits installiert ist <a class="header-anchor" href="#_1-uberprufen-ob-java-bereits-installiert-ist" aria-label="Permalink to “1. Überprüfen, ob Java bereits installiert ist”">​</a></h2><p>Öffne ein Terminal und gib <code>java -version</code> ein, drücke anschließend <kbd>Enter</kbd>.</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="Kommandozeile mit &quot;java -version&quot;" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Um den Großteil der modernen Minecraft-Versionen nutzen zu können, musst du Java 17 installiert haben. Wenn der Befehl eine Version niedriger als 17 anzeigt, musst du deine bestehende Java-Installation aktualisieren.</p></div><h2 id="_2-java-17-herunterladen-und-installieren" tabindex="-1">2. Java 17 herunterladen und installieren <a class="header-anchor" href="#_2-java-17-herunterladen-und-installieren" aria-label="Permalink to “2. Java 17 herunterladen und installieren”">​</a></h2><p>Wir empfehlen OpenJDK 17, welches auf den meisten Linux-Distributionen verfügbar ist.</p><h3 id="arch-linux" tabindex="-1">Arch Linux <a class="header-anchor" href="#arch-linux" aria-label="Permalink to “Arch Linux”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Für mehr Informationen über die Installation von Java auf Arch Linux, schaue in das <a href="https://wiki.archlinux.org/title/Java" target="_blank" rel="noreferrer">Arch Linux Wiki</a>.</p></div><p>Du kannst die aktuellste JRE aus den offiziellen Repositories installieren:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Wenn du einen Server betreibst, für den du keine grafische Oberfläche benötigst, kannst du stattdessen die Headless-Version installieren:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Wenn du planst Mods zu entwickeln, brauchst du stattdessen die JDK:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jdk-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="debian-ubuntu" tabindex="-1">Debian/Ubuntu <a class="header-anchor" href="#debian-ubuntu" aria-label="Permalink to “Debian/Ubuntu”">​</a></h3><p>Du kannst Java 17 über <code>apt</code> mit dem folgenden Befehl installieren:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openjdk-17-jdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="fedora" tabindex="-1">Fedora <a class="header-anchor" href="#fedora" aria-label="Permalink to “Fedora”">​</a></h3><p>Du kannst Java 17 über <code>dnf</code> mit dem folgenden Befehl installieren:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-17-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Wenn du keine grafische Oberfläche benötigst, kannst du stattdessen die Headless-Version installieren:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-17-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Wenn du planst Mods zu entwickeln, brauchst du stattdessen die JDK:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-17-openjdk-devel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="andere-linux-distributionen" tabindex="-1">Andere Linux Distributionen <a class="header-anchor" href="#andere-linux-distributionen" aria-label="Permalink to “Andere Linux Distributionen”">​</a></h3><p>Wenn deine Distribution oben nicht gelistet ist, kannst du die aktuellste JRE von <a href="https://adoptium.net/temurin/" target="_blank" rel="noreferrer">Adoptium</a> herunterladen</p><p>Du solltest einen alternativen Leitfaden für deine Distribution verwenden, wenn du Mods entwickeln willst.</p><h2 id="_3-verifizieren-dass-java-17-installiert-ist" tabindex="-1">3. Verifizieren, dass Java 17 installiert ist <a class="header-anchor" href="#_3-verifizieren-dass-java-17-installiert-ist" aria-label="Permalink to “3. Verifizieren, dass Java 17 installiert ist”">​</a></h2><p>Sobald die Installation abgeschlossen ist, kannst du überprüfen, ob Java 17 installiert ist, indem du die Kommandozeile erneut öffnest und &quot;java -version&quot; eingibst.</p><p>Wenn der Befehl erfolgreich ausgeführt wird, wird die Java-Version wie zuvor gezeigt angezeigt:</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="Kommandozeile mit &quot;java -version&quot;" loading="lazy"></p>`,33)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};